 using System;
 using System.Runtime.CompilerServices;
 using System.Runtime.InteropServices;
 using System.Runtime.Intrinsics;
 using System.Runtime.Intrinsics.X86;
 using System.Runtime.Intrinsics.Arm;

 namespace ByteBitReverse;

 public class BitReverser
 {
     // Lookup table: reversed nibble values (0x0→0x0, 0x1→0x8, …, 0xF→0xF)
     private static ReadOnlySpan<byte> NibbleLut =>
     [
         0x00, 0x08, 0x04, 0x0C, 0x02, 0x0A, 0x06, 0x0E,
         0x01, 0x09, 0x05, 0x0D, 0x03, 0x0B, 0x07, 0x0F
     ];

     // Full 256-byte scalar lookup table
     private static readonly byte[] ScalarLut = BuildScalarLut();

     private static byte[] BuildScalarLut()
     {
         var lut = new byte[256];
         ReadOnlySpan<byte> nib = NibbleLut;
         for (int i = 0; i < 256; i++)
             lut[i] = (byte)((nib[i & 0xF] << 4) | nib[i >> 4]);
         return lut;
     }

     public static void ReverseInPlace(Span<byte> data)
     {
         if (Avx2.IsSupported)
         {
             ReverseAvx2(data);
             return;
         }

         if (Ssse3.IsSupported)
         {
             ReverseSsse3(data);
             return;
         }

         if (AdvSimd.IsSupported)
         {
             ReverseNeon(data);
             return;
         }

         ReverseScalar(data);
     }

     [MethodImpl(MethodImplOptions.AggressiveInlining)]
     private static void ReverseAvx2(Span<byte> data)
     {
         var nibLut = Vector256.Create(NibbleLut[0], NibbleLut[1], NibbleLut[2], NibbleLut[3],
             NibbleLut[4], NibbleLut[5], NibbleLut[6], NibbleLut[7],
             NibbleLut[8], NibbleLut[9], NibbleLut[10], NibbleLut[11],
             NibbleLut[12], NibbleLut[13], NibbleLut[14], NibbleLut[15],
             NibbleLut[0], NibbleLut[1], NibbleLut[2], NibbleLut[3],
             NibbleLut[4], NibbleLut[5], NibbleLut[6], NibbleLut[7],
             NibbleLut[8], NibbleLut[9], NibbleLut[10], NibbleLut[11],
             NibbleLut[12], NibbleLut[13], NibbleLut[14], NibbleLut[15]);
         var mask = Vector256.Create((byte)0x0F);

         ref byte ptr = ref MemoryMarshal.GetReference(data);
         int i = 0;
         int len = data.Length;

         // Process 32 bytes at a time
         for (; i + 32 <= len; i += 32)
         {
             var vec = Vector256.LoadUnsafe(ref ptr, (nuint)i);
             var lo = Avx2.And(vec, mask);
             var hi = Avx2.And(Avx2.ShiftRightLogical(vec.AsUInt16(), 4).AsByte(), mask);
             var revLo = Avx2.Shuffle(nibLut, lo);
             var revHi = Avx2.Shuffle(nibLut, hi);
             var result = Avx2.Or(Avx2.ShiftLeftLogical(revLo.AsUInt16(), 4).AsByte(), revHi);
             result.StoreUnsafe(ref ptr, (nuint)i);
         }

         // Scalar tail
         byte[] lut = ScalarLut;
         for (; i < len; i++)
             Unsafe.Add(ref ptr, i) = lut[Unsafe.Add(ref ptr, i)];
     }

     [MethodImpl(MethodImplOptions.AggressiveInlining)]
     private static void ReverseSsse3(Span<byte> data)
     {
         var nibLut = Vector128.Create(NibbleLut);
         var mask = Vector128.Create((byte)0x0F);

         ref byte ptr = ref MemoryMarshal.GetReference(data);
         int i = 0;
         int len = data.Length;

         for (; i + 16 <= len; i += 16)
         {
             var vec = Vector128.LoadUnsafe(ref ptr, (nuint)i);
             var lo = Sse2.And(vec, mask);
             var hi = Sse2.And(Sse2.ShiftRightLogical(vec.AsUInt16(), 4).AsByte(), mask);
             var revLo = Ssse3.Shuffle(nibLut, lo);
             var revHi = Ssse3.Shuffle(nibLut, hi);
             var result = Sse2.Or(Sse2.ShiftLeftLogical(revLo.AsUInt16(), 4).AsByte(), revHi);
             result.StoreUnsafe(ref ptr, (nuint)i);
         }

         byte[] lut = ScalarLut;
         for (; i < len; i++)
             Unsafe.Add(ref ptr, i) = lut[Unsafe.Add(ref ptr, i)];
     }

     [MethodImpl(MethodImplOptions.AggressiveInlining)]
     private static void ReverseNeon(Span<byte> data)
     {
         var nibLut = Vector128.Create(NibbleLut);
         var mask = Vector128.Create((byte)0x0F);

         ref byte ptr = ref MemoryMarshal.GetReference(data);
         int i = 0;
         int len = data.Length;

