             var vec = Vector128.LoadUnsafe(ref ptr, (nuint)i);
             var lo = vec & mask;
             var hi = (vec >>> 4) & mask;
             var revLo = Vector128.Shuffle(nibLut, lo);
             var revHi = Vector128.Shuffle(nibLut, hi);
             var result = (revLo << 4) | revHi;
             result.StoreUnsafe(ref ptr, (nuint)i);
         }

         byte[] lut = ScalarLut;
         for (; i < len; i++)
             Unsafe.Add(ref ptr, i) = lut[Unsafe.Add(ref ptr, i)];
     }

